import React, { useState } from 'react';
import axios from 'axios';
import './Auth.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

function AdminUsers() {
  const [form, setForm] = useState({
    nombre: '',
    apellidos: '',
    codigo_estudiante: '',
    email: '',
    contrasena: '',
    cedula: '',
    rol: 'ESTUDIANTE',
  });
  const [mensaje, setMensaje] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError('');
    setMensaje('');
    setLoading(true);

    try {
      const token = localStorage.getItem('token');
      await axios.post(`${API_URL}/api/admin/usuarios`, form, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      setMensaje('Usuario creado correctamente');
      setForm({
        nombre: '',
        apellidos: '',
        codigo_estudiante: '',
        email: '',
        contrasena: '',
        cedula: '',
        rol: 'ESTUDIANTE',
      });
    } catch (err) {
      setError(err.response?.data?.message || 'Error al crear usuario');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <h1>Crear usuario</h1>
        <p>Solo administradores: crea estudiantes o empleados.</p>

        {mensaje && <div className="auth-success">{mensaje}</div>}
        {error && <div className="auth-error">{error}</div>}

        <form className="auth-form" onSubmit={handleSubmit}>
          <div className="auth-field">
            <label htmlFor="nombre">Nombre</label>
            <input id="nombre" name="nombre" value={form.nombre} onChange={handleChange} required />
          </div>

          <div className="auth-field">
            <label htmlFor="apellidos">Apellidos</label>
            <input id="apellidos" name="apellidos" value={form.apellidos} onChange={handleChange} required />
          </div>

          <div className="auth-field">
            <label htmlFor="cedula">Cedula</label>
            <input id="cedula" name="cedula" value={form.cedula} onChange={handleChange} />
          </div>

          <div className="auth-field">
            <label htmlFor="codigo_estudiante">Codigo</label>
            <input
              id="codigo_estudiante"
              name="codigo_estudiante"
              value={form.codigo_estudiante}
              onChange={handleChange}
              required
            />
          </div>

          <div className="auth-field">
            <label htmlFor="email">Correo</label>
            <input id="email" name="email" type="email" value={form.email} onChange={handleChange} required />
          </div>

          <div className="auth-field">
            <label htmlFor="contrasena">Contrasena</label>
            <input
              id="contrasena"
              name="contrasena"
              type="password"
              value={form.contrasena}
              onChange={handleChange}
              required
            />
          </div>

          <div className="auth-field">
            <label htmlFor="rol">Rol</label>
            <select id="rol" name="rol" value={form.rol} onChange={handleChange}>
              <option value="ESTUDIANTE">ESTUDIANTE</option>
              <option value="EMPLEADO">EMPLEADO</option>
            </select>
          </div>

          <div className="auth-actions">
            <button className="auth-button" type="submit" disabled={loading}>
              {loading ? 'Creando...' : 'Crear usuario'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AdminUsers;
